-- STEP 1: query [kommuner]
SELECT  kommunenummer, kommunenavn, ST_AsGeoJSON(ST_Transform(omrade, 4326)) AS geom_geojson FROM kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE '%Drammen%';

-- STEP BOUNDARY --

-- STEP 2: query [flomsoner]
SELECT  ST_AsGeoJSON(ST_Transform(omrade, 4326)) AS geom_geojson FROM flomsoner_76d14d5fe2fd4a29bfffc266fdcdd820.flomareal WHERE gjentaksintervall = 200 AND ST_Intersects(omrade, ST_Transform(ST_GeomFromGeoJSON('{"type":"Feature","geometry":{{geom_geojson}},"properties":{}}'), 25833));

